SET NAMES utf8mb4;

DROP TABLE IF EXISTS clues_cdmx;
CREATE TABLE clues_cdmx (
    clues VARCHAR(20) PRIMARY KEY,
    nombre_unidad VARCHAR(255),
    nombre_comercial VARCHAR(255),
    institucion VARCHAR(150),
    tipo_establecimiento VARCHAR(120),
    tipologia VARCHAR(160),
    alcaldia VARCHAR(100),
    latitud DECIMAL(10,7),
    longitud DECIMAL(10,7),
    estatus_operacion VARCHAR(100)
) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci;











